// 树状数组
void solve(int CASE)
{
	ll n, k; cin >> n >> k;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];

	var p = vector<pll>(n + 2); // { 前缀和, 下标 }
	ll pre = 0;
	p[1] = { pre, 1 };
	fa(i, 1, n) {
		pre += a[i];
		p[i + 1] = { pre, i + 1 };
	}
	sort(all1(p));

	var t = FenwickTree<ll>(n + 2);
	var sum = vector<ll>(n + 2);
	int j = 1; sum[j] = p[j].px;
	ll ans = 0;
	fa(i, 2, n + 1) {
		const var& [a, id] = p[i];
		sum[i] += a;
		while (j <= i and sum[i] - sum[j] >= k) {
			// 前缀满足条件，就放入树状数组
			const var& [na, nid] = p[j];
			t.update(nid, 1);
			j++;
		}
		ans += t.query(id);
	}
	cout << ans << endl;
	return;
}

// 动态开点线段树
struct Info {
	Info() :cnt(0) {};
	Info(int cnt) :cnt(cnt) {};

	// 要维护的值
	int cnt;
	void apply(const Info& v) {
		// 如何单点修改
		cnt += v.cnt;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.cnt = a.cnt + b.cnt;
	return c;
}

const ll Y = 3e14;
const ll MaxNodes = 2e5 * 64;
const ll DIFF = 1e14 + 10;
DynamicSegmentTree<Info, Y, MaxNodes> seg;
void solve(int CASE)
{
	ll n, k; cin >> n >> k;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	ll ans = 0, pre = 0;
	seg.modify(pre + DIFF, 1);
	fa(i, 1, n) {
		pre += a[i];
		ll t = pre - k;
		ans += seg.query(1, t + DIFF).cnt;
		seg.modify(pre + DIFF, 1);
	}
	cout << ans << endl;
	return;
}
